import pika

# Establish connection to RabbitMQ server
connection = pika.BlockingConnection(pika.ConnectionParameters('localhost', 5672))

# Create a channel
channel = connection.channel()

# Define queue
channel.queue_declare(queue='tasks')

# Publisher
def publish_task(task_message):
    channel.basic_publish(exchange='', routing_key='tasks', body=task_message.encode())

# Consumer
def consume_task():
    channel.basic_consume(queue='tasks', on_message_callback=callback)

    channel.start_consuming()

def callback(ch, method, properties, body):
    task_message = body.decode()
    # Process task here
    print(f"Processing task: {task_message}")

    ch.basic_ack(delivery_tag=method.delivery_tag)

# Example usage
task_message = "Perform task A"
publish_task(task_message)

consume_task()

# Close the connection
connection.close()